```plantuml
@startuml
skinparam classAttributeIconSize 0

package javafx {
    abstract class Application {
        + start(stage : Stage)
    }
}

class Main {
        + {static} main(args : String[])
}

class App {
        + {static} main(args : String[])
        + start(stage : Stage)
}

class ConnexionView {
}

class ConnexionController {
        - username : TextField
        - password : PasswordField
        + login()
}

class HomeView {
}

class HomeController {
        + loadFolder()
        + logout()
}

class FolderView {
}

class FolderController <<ConcretSubject>> {
        + addAntecedent()
        + addVisit()
        + restoreFolder()
        + saveFolder()
}

package java.util {
    class Observable <<Subject>> {
        + addObserver(Observer o)
        + deleteObserver(Observer o)
        + notifyObservers()
        + notifyObservers(arg: Object)
        + setChanged()
    }
    interface Observer {
        + update(obs : java.util.Observable, arg: Object)
    }
}

interface Authenticable {
        + login(user: String, pass: String) : boolean
}

class Session <<Director>> {
        + login (user: String, pass: String) : boolean
        + downloadFolder() : boolean
        + resetFolder() : boolean
        + getCurrentFolder(): Folder
        + getVisits(): Set<Visit>
        + getAntecedents(): Set<Antecedent>
        + getDoctor(): Doctor
        + <<construct()>> createNewVisit(treatment: String, diagnostic: String , ...)
}

class DataSource {
        + findById(id : String) : Folder
        + findByUsernameAndPassword (username : String, password: String) : User
        + update(f : Folder) : boolean
        - archiveModification(f : Folder) : boolean
        - encryptPasswordToSHA1(pass: String) : String
}

interface Editable {
        + update(f : Folder)
}

interface Searchable {
        + findById(id : String) : Folder
        + findByUsernameAndPassword (username : String, password: String) : User
}

class User {
        - username : String
        - password : String
}

class VisitBuilder <<ConcreteBuilder>> {
        + <<buildPart()>> setTreatment(designation : String)
        + <<buildPart()>> setTreatment(designation : String)
        + <<result()>> build(): Visit
}

class Folder <<Prototype>> <<ConcretObserver>> {
        + addVisit(v: Visit)
        + addAntecedent(a: Antecedent)
        + getVisits() : List<Visit>
        + getAntecedents() : List<Antecedent>
        + <<clone>> duplicate(): Folder
        + update()
}

class Visit <<Product>> {
        - date : Date
        - summary : String
        - notes : String
}

class Antecedent {
        - beginning : Date
        - end : Date
}

class Doctor {
        - lastname : String
        - firstname : String
        - permit : String
        - speciality : String
}

class Treatment <<ProductPart>> {
        - designation : String
}

class Diagnostic <<ProductPart>> {
        - designation : String
}

class Patient {
        - lastname : String
        - firstname : String
        - dateOfBirth : Date
        - birthCity : String
        - insuranceNumber : String
        - father : String
        - mother : String
}

class Establishment {
        - identification : String
        - designation : String
}

enum Gender {
        MALE
        FEMALE
        OTHER
}

class Contact {
        - address : String
        - phone : String
        - email : String
}

Application <|-- App
Main ..> App
App ..> Session
ConnexionView -- ConnexionController
ConnexionController ..> Session
HomeView -- HomeController
HomeController ..> Session
FolderView -- FolderController
FolderController --> Session
Observable <|-- FolderController
Observable "1" o-- "0..n" Observer
Observer <|.. Folder
Authenticable <|.. Session
Session --> "0..1\nuser" User
Session --> "0..1\nnewVisit" Visit
Session --> "0..1\noriginalFolder" Folder
Session --> "0..1currentFolder" Folder
Session -> DataSource
DataSource ..> Editable
DataSource ..> Searchable
VisitBuilder ..> Visit
Folder *-- "*" Visit : visits
Folder *-- "*" Antecedent : antecedents
Folder --> "1\nowner" Patient
Visit *-- "1\ndoctor" Doctor
Visit *-- "0..1\ntreatement" Treatment
Visit *-- "0..1\ndiagnostic" Diagnostic
Antecedent *-- "1\ndoctor prescriber" Doctor
Antecedent *-- "1\ntreatement" Treatment
Antecedent *-- "1\\diagnostic" Diagnostic
User <|-- Doctor
Doctor *-- "1\nestablishment" Establishment
Patient *-- "1\ngender" Gender
Patient *-- "1\\contact" Contact

@enduml
```
